    // 12. 添加签名人
    doc.setFontSize(14);
    doc.setFont('times', 'bold');
    doc.setTextColor(0, 0, 0); // 纯黑色
    doc.text('Prof. Dr. Linda Foster', pageWidth / 4, pageHeight - 40, {
      align: 'center'
    });
    doc.text('Prof. Dr. James Carpenter', pageWidth * 3 / 4, pageHeight - 40, {
      align: 'center'
    });
    doc.setFontSize(12);
    doc.setFont('times', 'normal');
    doc.setTextColor(0, 0, 0); // 纯黑色
    doc.text('University President', pageWidth / 4, pageHeight - 30, {
      align: 'center'
    });
    doc.text('Program Director', pageWidth * 3 / 4, pageHeight - 30, {
      align: 'center'
    });

    // 13. 添加日期和证书ID
    doc.setFontSize(12);
    doc.setTextColor(0, 0, 0); // 纯黑色
    doc.text(`Date: ${this.formatDate(certificate.date)}`, 30, pageHeight - 15);
    doc.text(`Certificate ID: ${certificate.certificateId}`, pageWidth - 30, pageHeight - 15, {
      align: 'right'
    });

    // 14. 添加认证标志 - 更明显的样式
    doc.setDrawColor(0, 0, 0); // 黑色边框
    doc.setLineWidth(2);
    doc.circle(pageWidth / 2, pageHeight - 40, 15, 'S');
    doc.setTextColor(0, 0, 0); // 纯黑色
    doc.setFontSize(12);
    doc.setFont('helvetica', 'bold');
    doc.text('VERIFIED', pageWidth / 2, pageHeight - 40, {
      align: 'center',
      baseline: 'middle'
    });

    // 15. 水印 - 使用更明显的水印
    doc.saveGraphicsState();
    doc.setGState(new doc.GState({
      opacity: 0.5
    })); // 增加不透明度到0.5
    doc.setTextColor(0, 0, 0); // 纯黑色水印
    doc.setFontSize(120);
    doc.setFont('helvetica', 'bold');
    doc.translate(pageWidth / 2, pageHeight / 2);
    doc.rotate(-30);
    doc.text('SIU', 0, 0, {
      align: 'center'
    });
    doc.restoreGraphicsState();
  }

