   * @param {string} url - 由URL.createObjectURL创建的URL
   */
  static safeRevokeURL(url) {
    if (url && typeof url === 'string' && url.startsWith('blob:')) {
      try {
        URL.revokeObjectURL(url);
      } catch (error) {
        console.error('Failed to revoke object URL:', error);
      }
    }
  }

  /**
   * 下载PDF证书
   * @param {Object} certificate - 证书数据
   */
  static downloadPDF(certificate) {
    try {
      if (!certificate) {
        throw new Error('证书数据不能为空');
      }

      // 创建PDF文档
      const doc = this.createPDF(certificate);

      // 设置下载文件名
      const fileName = `${certificate.name}_Certificate_${certificate.certificateId}.pdf`;

      // 使用高质量设置保存PDF
      doc.output('save', {
        filename: fileName,
        compress: false,
        // 禁用压缩保持最高质量
        precision: 16 // 最高精度
      });
      console.log('证书下载成功:', fileName);
      return true;
    } catch (error) {
      console.error('下载PDF时出错:', error);
      alert('下载证书时出错，请重试');
      return false;
    }
  }

