      try {
        // 创建PDF
        const doc = this.createPDF(certificate);

        // 生成PDF并下载
        const pdfBlob = doc.output('blob');
        const pdfUrl = URL.createObjectURL(pdfBlob);

        // 创建下载链接
        const link = document.createElement('a');
        link.href = pdfUrl;
        link.download = `${certificate.name}-${certificate.certificateId}.pdf`;

        // 模拟点击下载
        document.body.appendChild(link);
        link.click();

        // 安全移除链接
        setTimeout(() => {
          document.body.removeChild(link);
          URL.revokeObjectURL(pdfUrl);
        }, 100);
        console.log('高对比度PDF证书生成并下载成功');
        return true;
      } catch (pdfError) {
        console.error('高对比度PDF生成失败，尝试备用方法:', pdfError);
        // 继续使用备用方法
      }

      // 使用原始方法下载
      return this.downloadPDF(certificate);
    } catch (error) {
      console.error('下载证书时出错:', error);
      alert('下载证书时出错，请重试');
      return false;
    }
  }
}
