import { jsPDF } from 'jspdf';
import i18next from 'i18next';
import certificateConfig from '../config/certificateTemplates.json';
import QRCode from 'qrcode';

// 导入crypto模块（如果在Node.js环境中）或使用浏览器兼容的哈希函数
// 浏览器兼容的哈希函数
function sha256(str) {
  return crypto.subtle.digest('SHA-256', new TextEncoder().encode(str)).then(hashBuffer => {
      const hashArray = Array.from(new Uint8Array(hashBuffer));
      const hashHex = hashArray.map(b => b.toString(16).padStart(2, '0')).join('');
      return hashHex;
    });
}

/**
 * 证书生成服务 - 用于创建可下载的证书PDF
 */
class CertificateGenerator {
  /**
   * 根据证书数据生成PDF证书
   * @param {Object} certificate - 证书数据
   * @returns {Promise<Blob>} 返回PDF Blob
   */
  static generateCertificatePDF(certificate) {
    return new Promise((resolve, reject) => {
      try {
        // 获取当前语言
        const currentLanguage = i18next.language;
        const isEnglish = currentLanguage === 'en' || currentLanguage.startsWith('en-');

        // 创建PDF文档 (A4横向)
        const doc = new jsPDF({
          orientation: 'landscape',
          unit: 'mm',
          format: 'a4',
          compress: false, // 禁用压缩以获得更清晰的输出
          putOnlyUsedFonts: true,
          floatPrecision: 16, // 使用高精度浮点数
        });

        // 设置文档属性
        doc.setProperties({
          title: `${certificate.name} - ${isEnglish && certificate.english_course ? certificate.english_course : certificate.course} Certificate`,
          subject: 'Stratford International University Certificate',
          author: 'Stratford International University',
          keywords: 'certificate, education, diploma, blockchain, verified',
          creator: 'SIU Certificate System',
          resolution: 300, // 设置为高分辨率
        });

        // 直接绘制证书内容，不依赖外部SVG
        this.drawCertificateDirectly(doc, certificate);

            // 添加QR码 (用于验证)
        this.addVerificationQR(doc, certificate)
          .then(async () => {
            // 添加签名图片
            await this.addSignatureImages(doc, certificate);

            // 生成PDF并返回
            const pdfBlob = doc.output('blob');
            resolve(pdfBlob);
          })
          .catch(error => {
            console.error('添加验证QR码失败:', error);
            // 即使QR码失败，仍然尝试生成PDF
            const pdfBlob = doc.output('blob');
            resolve(pdfBlob);
          });
      } catch (error) {
        console.error('PDF生成错误:', error);
        reject(error);
      }
    });
  }

  /**
   * 预览证书 - 将证书数据填充到模板中
   * @param {Object} certificate - 证书数据
   * @returns {Promise<string>} 处理后的证书URL
   */
  static async previewCertificate(certificate) {
    try {
      // 如果证书已经处理过，直接返回
      if (certificate.processedImage) {
        return certificate.processedImage;
      }

      // 使用指定的模板或默认使用精美证书模板
      const templateUrl = certificate.templatePath || '/templates/certificate-premium.svg';

      // 通过fetch获取SVG模板
      const response = await fetch(templateUrl);
      if (!response.ok) {
        throw new Error(`无法加载证书模板: ${response.statusText}`);
      }

      let svgContent = await response.text();

      // 替换占位符
      svgContent = svgContent.replace(/\[RECIPIENT_NAME\]/g, certificate.name || 'Certificate Recipient');
      svgContent = svgContent.replace(/\[PROGRAM\]/g, certificate.course || 'Certificate Program');
      svgContent = svgContent.replace(/\[ISSUE_DATE\]/g, this.formatDate(certificate.date) || 'Certificate Issue Date');
      svgContent = svgContent.replace(/\[CERTIFICATE_NUMBER\]/g, certificate.certificateId || 'SIU-XXXX-XXXX');

      // 创建Blob和URL
      const blob = new Blob([svgContent], { type: 'image/svg+xml' });
      const processedImageUrl = URL.createObjectURL(blob);

      // 保存处理后的图像URL
      certificate.processedImage = processedImageUrl;

      console.log('证书SVG生成成功:', templateUrl);
      return processedImageUrl;
    } catch (error) {
      console.error('处理证书时出错:', error);
      return this.generateErrorImage(certificate);
    }
  }

  /**
   * 创建高对比度的证书SVG
   * @param {Object} certificate - 证书数据
   * @returns {string} SVG内容
   */
  static createHighContrastCertificateSVG(certificate) {
    // 颜色定义
    const goldColor = '#AD974F'; // 金色
    const blueColor = '#003087'; // 深蓝色
    const backgroundColor = '#FFF8F0'; // 米色背景

    // 格式化日期
    const formattedDate = this.formatDate(certificate.date);

    // 创建SVG字符串
    return `
    <svg width="1200" height="900" xmlns="http://www.w3.org/2000/svg">
      <!-- 米色背景 -->
      <rect width="1200" height="900" fill="${backgroundColor}" />

      <!-- 金色边框 -->
      <rect x="30" y="30" width="1140" height="840" fill="none" stroke="${goldColor}" stroke-width="6" />

      <!-- 学校标志 -->
      <circle cx="600" cy="150" r="85" fill="none" stroke="${goldColor}" stroke-width="3" /> <!-- 金色外圆 -->
      <circle cx="600" cy="150" r="80" fill="${blueColor}" stroke="none" /> <!-- 深蓝色内圆 -->
      <text x="600" y="150" font-family="Arial, sans-serif" font-size="80" font-weight="bold" text-anchor="middle" dominant-baseline="middle" fill="#FFFFFF">SIU</text> <!-- 白色文字 -->

      <!-- 学校名称 -->
      <text x="600" y="280" font-family="Times New Roman, serif" font-size="45" font-weight="bold" text-anchor="middle" fill="${blueColor}">STRATFORD INTERNATIONAL UNIVERSITY</text>

      <!-- 证书标题 -->
      <text x="600" y="360" font-family="Times New Roman, serif" font-size="65" font-weight="bold" text-anchor="middle" fill="${goldColor}">DIPLOMA</text>

      <!-- 证书文本 -->
      <text x="600" y="430" font-family="Times New Roman, serif" font-size="28" text-anchor="middle" fill="#000000">This is to certify that</text>

      <!-- 学生姓名 -->
      <text x="600" y="500" font-family="Times New Roman, serif" font-size="48" font-weight="bold" text-anchor="middle" fill="#000000">${certificate.name}</text>

      <!-- 课程描述 -->
      <text x="600" y="570" font-family="Times New Roman, serif" font-size="28" text-anchor="middle" fill="#000000">has successfully completed the online degree</text>

      <!-- 课程名称 -->
      <text x="600" y="640" font-family="Times New Roman, serif" font-size="40" font-style="italic" font-weight="bold" text-anchor="middle" fill="${goldColor}">${certificate.course}</text>

      <!-- 完成声明 -->
      <text x="600" y="700" font-family="Times New Roman, serif" font-size="22" text-anchor="middle" fill="#000000">together with all the rights, privileges and honours which appertain thereto.</text>

      <!-- 日期标签 -->
      <text x="600" y="750" font-family="Times New Roman, serif" font-size="22" text-anchor="middle" fill="#000000">Awarded Date</text>

      <!-- 日期 -->
      <text x="600" y="780" font-family="Times New Roman, serif" font-size="26" font-weight="bold" text-anchor="middle" fill="#000000">${formattedDate}</text>

      <!-- 签名 -->
      <text x="350" y="780" font-family="Times New Roman, serif" font-size="24" font-style="italic" text-anchor="middle" fill="#000000">Linda Foster</text>
      <text x="850" y="780" font-family="Times New Roman, serif" font-size="24" font-style="italic" text-anchor="middle" fill="#000000">James Carpenter</text>

      <!-- 签名线 -->
      <line x1="250" y1="800" x2="450" y2="800" stroke="#000000" stroke-width="1" />
      <line x1="750" y1="800" x2="950" y2="800" stroke="#000000" stroke-width="1" />

      <!-- 签名人 -->
      <text x="350" y="820" font-family="Times New Roman, serif" font-size="18" text-anchor="middle" fill="#000000">Prof. Dr. Linda Foster</text>
      <text x="350" y="840" font-family="Times New Roman, serif" font-size="16" text-anchor="middle" fill="#000000">University President</text>

      <text x="850" y="820" font-family="Times New Roman, serif" font-size="18" text-anchor="middle" fill="#000000">Prof. Dr. James Carpenter</text>
      <text x="850" y="840" font-family="Times New Roman, serif" font-size="16" text-anchor="middle" fill="#000000">Program Director</text>

      <!-- 证书ID -->
      <text x="1150" y="880" font-family="Arial, sans-serif" font-size="12" text-anchor="end" fill="#666666">Certificate ID: ${certificate.certificateId}</text>

      <!-- 装饰星形 -->
      <path d="M100,100 L115,70 L130,100 L160,115 L130,130 L115,160 L100,130 L70,115 Z" fill="${goldColor}" opacity="0.2" />
      <path d="M1100,100 L1115,70 L1130,100 L1160,115 L1130,130 L1115,160 L1100,130 L1070,115 Z" fill="${goldColor}" opacity="0.2" />
      <path d="M100,800 L115,770 L130,800 L160,815 L130,830 L115,860 L100,830 L70,815 Z" fill="${goldColor}" opacity="0.2" />
      <path d="M1100,800 L1115,770 L1130,800 L1160,815 L1130,830 L1115,860 L1100,830 L1070,815 Z" fill="${goldColor}" opacity="0.2" />

      <!-- 中央水印 -->
      <g transform="translate(600, 450)" opacity="0.1">
        <circle cx="0" cy="0" r="100" fill="${blueColor}" />
        <text x="0" y="0" font-family="Arial, sans-serif" font-size="120" font-weight="bold" text-anchor="middle" dominant-baseline="middle" fill="#FFFFFF">SIU</text>
      </g>
    </svg>
    `;
  }

  /**
   * 创建PDF证书
   * @param {Object} certificate - 证书数据
   * @returns {jsPDF} jsPDF文档对象
   */
  static createPDF(certificate) {
    // 创建新的PDF文档，使用A4尺寸，横向
    const doc = new jsPDF({
              orientation: 'landscape',
              unit: 'mm',
      format: 'a4',
      compress: false, // 禁用压缩以获得更清晰的输出
      putOnlyUsedFonts: true,
      floatPrecision: 16, // 使用高精度浮点数
    });

    // 设置高分辨率输出 - 提高打印质量
    doc.setProperties({
      title: `Certificate - ${certificate.name}`,
      subject: `Certificate of Completion for ${certificate.course}`,
      author: 'Stratford International University',
      keywords: 'certificate, completion, education',
      creator: 'SIU Certificate System',
      resolution: 300, // 设置为高分辨率
    });

    // 直接绘制证书内容
    this.drawCertificateDirectly(doc, certificate);

    return doc;
  }

  /**
   * 直接在PDF上绘制证书内容，不依赖任何外部SVG或图像
   * @param {jsPDF} doc - jsPDF文档对象
   * @param {Object} certificate - 证书数据
   */
  static drawCertificateDirectly(doc, certificate) {
    // 获取页面尺寸
    const pageWidth = doc.internal.pageSize.getWidth();
    const pageHeight = doc.internal.pageSize.getHeight();

    // 1. 创建纯白色背景
    doc.setFillColor(255, 255, 255);
    doc.rect(0, 0, pageWidth, pageHeight, 'F');

    // 2. 添加双重边框 - 更粗的边框增强可见性
    doc.setDrawColor(0, 0, 0); // 纯黑色边框
    doc.setLineWidth(2); // 更粗的边框
    doc.rect(10, 10, pageWidth - 20, pageHeight - 20, 'S');

    doc.setDrawColor(0, 0, 0); // 内边框也用纯黑色
    doc.setLineWidth(1);
    doc.rect(15, 15, pageWidth - 30, pageHeight - 30, 'S');

    // 3. 添加大学标志 - 修改为更醒目的双层圆环设计
    // 外圆 - 金色边框
    doc.setDrawColor(173, 151, 79); // 金色边框 #AD974F
    doc.setLineWidth(2);
    doc.circle(pageWidth / 2, 40, 20, 'S');

    // 内圆 - 深蓝色填充
    doc.setFillColor(0, 48, 135); // 深蓝色填充 #003087
    doc.circle(pageWidth / 2, 40, 18, 'F');

    // 文字 - 白色SIU
    doc.setTextColor(255, 255, 255); // 纯白色文字
    doc.setFontSize(18); // 增大字体
    doc.setFont('helvetica', 'bold');
    doc.text('SIU', pageWidth / 2, 40, { align: 'center', baseline: 'middle' });

    // 添加内圆环 - 增强立体感
    doc.setDrawColor(255, 255, 255); // 白色内圆环
    doc.setLineWidth(0.5);
    doc.circle(pageWidth / 2, 40, 16, 'S');

    // 4. 添加学校名称 - 使用纯黑色
    doc.setTextColor(0, 0, 0); // 纯黑色文本
    doc.setFontSize(28); // 增大字体
    doc.setFont('times', 'bold');
    doc.text('STRATFORD INTERNATIONAL UNIVERSITY', pageWidth / 2, 65, { align: 'center' });

    // 5. 添加证书标题 - 使用纯黑色
    doc.setTextColor(0, 0, 0);
    doc.setFontSize(40); // 增大字体
    doc.setFont('times', 'bold');
    doc.text('CERTIFICATE OF COMPLETION', pageWidth / 2, 90, { align: 'center' });

    // 中文标题
    doc.setFontSize(24); // 增大字体
    doc.text('毕业证书', pageWidth / 2, 105, { align: 'center' });

    // 6. 添加证书文本
    doc.setFontSize(16); // 增大字体
    doc.setFont('times', 'normal');
    doc.text('The Stratford International University hereby certifies that', pageWidth / 2, 125, {
      align: 'center',
    });

    // 7. 添加姓名 - 带高亮背景和更明显的边框
    doc.setFillColor(240, 248, 255); // 浅蓝色背景
    doc.rect(pageWidth / 2 - 90, 135, 180, 25, 'F');
    doc.setDrawColor(0, 0, 0); // 黑色边框
    doc.setLineWidth(1);
    doc.rect(pageWidth / 2 - 90, 135, 180, 25, 'S'); // 添加边框
    doc.setFontSize(26); // 增大字体
    doc.setFont('times', 'bold');
    doc.setTextColor(0, 0, 0); // 纯黑色
    doc.text(certificate.name, pageWidth / 2, 150, { align: 'center' });

    // 8. 添加中间文本
    doc.setFontSize(16); // 增大字体
    doc.setFont('times', 'normal');
    doc.text('has fulfilled the requirements for the degree of', pageWidth / 2, 170, {
      align: 'center',
    });

    // 9. 添加课程名称 - 带高亮背景和更明显的边框
    doc.setFillColor(255, 248, 220); // 浅黄色背景
    doc.rect(pageWidth / 2 - 100, 180, 200, 25, 'F');
    doc.setDrawColor(0, 0, 0); // 黑色边框
    doc.setLineWidth(1);
    doc.rect(pageWidth / 2 - 100, 180, 200, 25, 'S'); // 添加边框
    doc.setFontSize(22); // 增大字体
    doc.setFont('times', 'bold');
    doc.setTextColor(0, 0, 0); // 纯黑色
    doc.text(certificate.course, pageWidth / 2, 195, { align: 'center' });

    // 10. 添加声明
    doc.setFontSize(14); // 增大字体
    doc.setFont('times', 'normal');
    doc.setTextColor(0, 0, 0); // 纯黑色
    doc.text(
      'and is awarded this Certificate of Completion with all rights, privileges, and honors appertaining thereto.',
      pageWidth / 2,
      215,
      { align: 'center' }
    );

    // 11. 添加签名线 - 更明显的线
    doc.setDrawColor(0, 0, 0);
    doc.setLineWidth(1.5); // 更粗的签名线
    doc.line(pageWidth / 4, pageHeight - 50, pageWidth / 4 + 60, pageHeight - 50);
    doc.line((pageWidth * 3) / 4 - 60, pageHeight - 50, (pageWidth * 3) / 4, pageHeight - 50);

    // 12. 添加签名人
    doc.setFontSize(14);
    doc.setFont('times', 'bold');
    doc.setTextColor(0, 0, 0); // 纯黑色
    doc.text('Prof. Dr. Linda Foster', pageWidth / 4, pageHeight - 40, { align: 'center' });
    doc.text('Prof. Dr. James Carpenter', (pageWidth * 3) / 4, pageHeight - 40, {
      align: 'center',
    });

    doc.setFontSize(12);
    doc.setFont('times', 'normal');
    doc.setTextColor(0, 0, 0); // 纯黑色
    doc.text('University President', pageWidth / 4, pageHeight - 30, { align: 'center' });
    doc.text('Program Director', (pageWidth * 3) / 4, pageHeight - 30, { align: 'center' });

    // 13. 添加日期和证书ID
    doc.setFontSize(12);
    doc.setTextColor(0, 0, 0); // 纯黑色
    doc.text(`Date: ${this.formatDate(certificate.date)}`, 30, pageHeight - 15);
    doc.text(`Certificate ID: ${certificate.certificateId}`, pageWidth - 30, pageHeight - 15, {
      align: 'right',
    });

    // 14. 添加认证标志 - 更明显的样式
    doc.setDrawColor(0, 0, 0); // 黑色边框
    doc.setLineWidth(2);
    doc.circle(pageWidth / 2, pageHeight - 40, 15, 'S');
    doc.setTextColor(0, 0, 0); // 纯黑色
    doc.setFontSize(12);
    doc.setFont('helvetica', 'bold');
    doc.text('VERIFIED', pageWidth / 2, pageHeight - 40, { align: 'center', baseline: 'middle' });

    // 15. 水印 - 使用更明显的水印
    doc.saveGraphicsState();
    doc.setGState(new doc.GState({ opacity: 0.5 })); // 增加不透明度到0.5
    doc.setTextColor(0, 0, 0); // 纯黑色水印
    doc.setFontSize(120);
    doc.setFont('helvetica', 'bold');
    doc.translate(pageWidth / 2, pageHeight / 2);
    doc.rotate(-30);
    doc.text('SIU', 0, 0, { align: 'center' });
    doc.restoreGraphicsState();
  }

  /**
   * 生成错误图像 - 用于在无法加载证书图像时显示
   * @param {Object} certificate - 证书数据
   * @returns {string} 图像URL
   */
  static generateErrorImage(certificate) {
    // 创建一个更专业的SVG，模仿真实证书但显示错误消息
    const svgContent = `
    <svg width="800" height="600" xmlns="http://www.w3.org/2000/svg" role="img" aria-labelledby="certificate-error-title certificate-error-desc">
      <title id="certificate-error-title">Certificate Error</title>
      <desc id="certificate-error-desc">Certificate image is not available for this certificate</desc>

      <!-- 使用柔和的背景色和更优雅的设计 -->
      <rect width="800" height="600" fill="#f8f9fa" stroke="#cccccc" stroke-width="2" />

      <!-- 添加内边框使其看起来更像证书 -->
      <rect x="20" y="20" width="760" height="560" fill="none" stroke="#aaaaaa" stroke-width="1" />

      <!-- 添加校徽样式图标 -->
      <circle cx="400" cy="150" r="70" fill="#f1f1f1" stroke="#999999" stroke-width="1" />
      <text x="400" y="150" font-family="Times New Roman, serif" font-size="40" text-anchor="middle" dominant-baseline="middle" fill="#999999">SIU</text>
      <circle cx="400" cy="150" r="55" fill="none" stroke="#999999" stroke-width="0.5" />

      <!-- 学校名称 -->
      <text x="400" y="250" font-family="Times New Roman, serif" font-size="24" font-weight="bold" text-anchor="middle" fill="#555555">STRATFORD INTERNATIONAL UNIVERSITY</text>

      <!-- 错误消息 - 提高可读性的样式 -->
      <text x="400" y="310" font-family="Arial, sans-serif" font-size="20" text-anchor="middle" fill="#666666" font-weight="bold">证书模板不可用</text>
      <text x="400" y="340" font-family="Arial, sans-serif" font-size="16" text-anchor="middle" fill="#666666">Certificate Template Not Available</text>

      <!-- 建议消息 -->
      <text x="400" y="380" font-family="Arial, sans-serif" font-size="14" text-anchor="middle" fill="#777777">请联系管理员获取新的证书模板</text>
      <text x="400" y="400" font-family="Arial, sans-serif" font-size="14" text-anchor="middle" fill="#777777">Please contact administrator for template update</text>

      <!-- 显示证书ID以便识别 -->
      <text x="400" y="460" font-family="Consolas, monospace" font-size="16" font-weight="bold" text-anchor="middle" fill="#333333">${certificate ? certificate.certificateId : 'Unknown ID'}</text>

      <!-- 添加装饰元素 -->
      <line x1="250" y1="500" x2="550" y2="500" stroke="#999999" stroke-width="1" stroke-dasharray="5,5" />
      <text x="400" y="520" font-family="Arial, sans-serif" font-size="12" text-anchor="middle" fill="#999999">系统已记录此错误 | Error logged</text>
    </svg>
    `;

    // 创建Blob和URL
    const blob = new Blob([svgContent], { type: 'image/svg+xml' });
    const errorImageUrl = URL.createObjectURL(blob);

    // 如果有证书对象，保存处理后的图像URL
    if (certificate) {
      certificate.processedImage = errorImageUrl;
      // 添加标记，表示这是错误图像
      certificate._isErrorImage = true;
      console.error(
        `证书模板不可用：ID=${certificate.certificateId}, 名称=${certificate.name}, 图像路径=${certificate.image || '未设置'}`
      );
    }

    return errorImageUrl;
  }

  /**
   * 格式化日期为更好的显示格式
   * @param {string} dateString - ISO日期字符串
   * @returns {string} 格式化的日期
   */
  static formatDate(dateString) {
    if (!dateString) return 'N/A';

    try {
      const date = new Date(dateString);

      // 检查日期是否有效
      if (isNaN(date.getTime())) {
        return dateString; // 如果无效，则返回原始字符串
      }

      // 格式化为 '15th December, 2023' 这样的格式
      const options = { year: 'numeric', month: 'long', day: 'numeric' };
      let formatted = date.toLocaleDateString('en-US', options);

      // 添加序数后缀 (1st, 2nd, 3rd, 4th 等)
      const day = date.getDate();
      const suffix = this.getOrdinalSuffix(day);

      // 替换日期中的数字为带有序数后缀的版本
      formatted = formatted.replace(String(day), `${day}${suffix}`);

      return formatted;
    } catch (error) {
      console.error('格式化日期时出错:', error);
      return dateString;
    }
  }

  /**
   * 获取数字的序数后缀 (st, nd, rd, th)
   * @param {number} n - 数字
   * @returns {string} 序数后缀
   */
  static getOrdinalSuffix(n) {
    if (n > 3 && n < 21) return 'th'; // 11th, 12th, 13th, ...
    switch (n % 10) {
      case 1:
        return 'st';
      case 2:
        return 'nd';
      case 3:
        return 'rd';
      default:
        return 'th';
    }
  }

  /**
   * 缩短哈希值为更友好的显示格式
   * @param {string} hash - 完整哈希值
   * @returns {string} 缩短的哈希值
   */
  static shortenHash(hash) {
    if (!hash) return 'N/A';

    // 如果哈希值很长，只保留前6位和后6位
    if (hash.length > 15) {
      return `${hash.substring(0, 6)}...${hash.substring(hash.length - 6)}`;
    }

    return hash;
  }

